    is_unlocked_by_default = true,
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Advanced Tips",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Here are a few tips to increase your productivity while playing FOUNDRY. This section is intended to be read by players who already know the general game mechanics. It provides valuable information for new players, but it may be overwhelming at first. Play a while and then come back to check the advanced stuff if you're new!",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "<b><u>Build Modes:</u></b> There are two build modes (snap / free), after you equip a buildable item you will always start in snap mode, which is going to try to place the structure by snapping it to the point you're looking at. There can be cases where this behavior is not desired as there might not be a point you can point at, for example extending a ledge of conveyor belts you are standing on - or if you want to build something in the air without reference point. For those cases you can use free mode, which will always place the structure at a certain distance in front of you.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "<b><u>Drag Modes:</u></b> Some objects which can be drag-built (click and drag to build multiple objects at once) have more than one drag mode. For example building blocks can be dragged as floor or as wall. If multiple drag modes are supported it will be indicated by the UI above your hotkey bar once the item is active.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "<b><u>Right-Click Item Equip:</u></b> Hotkey bar space is limited and often it is not feasible to drag a structure into your bar just to place a single object. By right-clicking the item in your inventory you will instantly equip it.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[<b><u>Upgrade Machinery:</u></b> Machines of the same type (f.i. Assembler I/Assembler II/...) can be replaced by selecting the machinery you want to upgrade to and looking at the one to replace.
Conveyor belts can be upgraded as well, in this case the whole connected belt will be replaced, but not across conveyor balancers or T-crossings.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "<b><u>Multiple Hotkey Bars:</u></b> Toggle between multiple hotkey bars by pressing <action=Cycle Hotkeybar>. In the settings you can change the amount of hotkey bars you want to use.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[<b><u>Move Multiple Items At Once:</u></b> 
- Shift+Left-Click tries to move the whole stack to the opposite inventory (e.g. in/out of a chest/machine). 
- Ctrl+Left-Click tries to move as many items as possible (multiple stacks, only same items as clicked one) to the opposite inventory.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "<b><u>Stack Splitting:</u></b> You can split a stack by Shift + Right-Click on its icon. This works on your own and any other inventory (e.g. chest, machine,...).",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[<b><u>Crafting:</u></b> You can craft more than one item by clicking on a recipe by using different click patterns: 
- Left-Click: Craft 1 item.
- Right-Click: Craft 5 items.
- Shift + Right-Click: Craft 100 items.
- Shift + Left-Click: Craft as many items as possible 
The number on the bottom right corner of the recipe shows you how many items can be crafted. All click patterns will create as many items as possible if there are not enough resources available.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "<b><u>Mass Destroy Items:</u></b> You can destroy all stacks of the same item in your inventory by holding down the Ctrl button while dropping an item on the destroy button in your inventory. This works on your own and any other inventory (e.g. chest, machine,...).",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "<b><u>Bulk Demolish:</u></b> You can destroy multiple structures at once. The Bulk Demolish mode (keybinding: <action=BulkDemolish>) lets you drag a box in two steps and will demolish all buildings inside once you confirm.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "<b><u>Pick Up Items From Conveyor Belt:</u></b> Items can be picked up from conveyor belts by looking at the conveyor belt and pressing <action=Conveyor Belt Item Pick Up>.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "<b><u>Copy Objects:</u></b> Pressing <action=Copy Target> while looking at any machine/object will copy it. Pressing <action=Copy Target With Settings> copies it with configured settings.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
