  ["_base_character_elevator"] = {
    identifier = "_base_character_elevator",
    category_id = "_base_buildings",
    sidebar_text = "Character Elevator",
    page_type = "PerCharacter",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Character Elevator",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The character elevator acts as common elevator where characters may travel to different configurable floors. After initial configuration the elevator can automatically build itself and dig its shaft if necessary. 

<b>The elevator has a connected high-voltage-cable along its side, you can connect power lines to every station, so they act as easy solution to convey high-voltage-power up or down.</b>

The elevator is blast resistant, you may use explosives in its vicinity.

Note: The elevator itself does not need power to function.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Configuration",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Start by placing the elevator building which will construct your first station. As stations can be moved during construction mode you don't have to place the initial building at the desired height of any future station, you can start your elevator construction wherever you want.

Then go to the screen panel inside the elevator cabin and open the configuration frame:
Here you can set all stations and their related height your elevator should consist of. 
After your list with stations is complete, press the "Confirm" button and your elevator will automatically enter construction mode and build itself. This way you can easily access the underground without the need to excavate a very large area.

You can enter edit mode at any time as long as the cabin is  not moving and modify your elevator again, allowing adding / deleting / moving stations.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Usage",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Enter the cabin and press the button of the station you want to go to.

If the cabin is not at your location it can be called by the button on the right side of the door.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_compass_co"] = {
    identifier = "_base_compass_co",
    category_id = "_base_ui",
    sidebar_text = "Compass & Clock Information",
    page_type = "Global",
    is_unlocked_by_default = true,
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Compass & Clock Information",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The compass at the top left of the screen shows the current orientation, world coordinates (X/Z) and elevation level (Y) of your character.

Below the compass you can see the current daytime in 24-hour format.

Further below you see the time of the next sunrise / sunset and when solar panels will start to generate power / when solar panels will stop to generate power, depending on which event will occur earlier. Solar panel indicators are hidden until you unlock solar panels.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/compass.jpg|dda264a61362cbc4f9eb36cc4e239d93",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_construction_industry"] = {
    identifier = "_base_construction_industry",
    category_id = "_base_general",
    sidebar_text = "Construction Industry",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Construction Industry",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The term "Construction Industry" stands for multiple buildings and the construction site system for Modular Buildings. If you're looking for more information on how to set up and configure Modular Buildings please take a look at the respective info database page about Modular Buildings.

Once a modular building has been configured and confirmed for construction, it acts as a construction site that needs to be built. First it requires resources (construction materials) to be delivered. In case of an adjustment or dismantling, it also needs construction rubble to be carried away.

Once the construction material has been delivered, it needs to be built through a construction ship and its construction drones.

Once that is done, the building becomes operational.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_construction_industry_04.jpg|b92bfcd71dc495245991b12177798f2e",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Construction Ship Port",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The Construction Ship Port houses a construction ship. Those ships will automatically fly to any construction site with any construction material available. They will hover over the construction site and gradually build them. There is no need to assign the construction ship to a construction site, everything is fully automated.

If multiple ports are built, all of them will help constructing the building, speeding up its construction time.

<b>Construction Ship Excavation:</b>
Construction Ships are able to excavate designated mining areas from the Excavation Drone Controller. Just mark the areas and construction ships will automatically fly there and excavate. This behavior can be disabled on the building's screen panel. For more information read the info database page for the "Excavation Drone Controller" (needs to be unlocked through research first).]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_construction_industry_01.jpg|39f707469eac6844593ea674ed3777ba",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Transport Ship Port",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Transport Ship Ports house four transport ships. Transport ships are automatically transporting goods from places that provide them (f.i. a Construction Warehouse) to places that request them (f.i. a construction site). Like the construction ships, the system is fully automated. As long a requested item is provided somewhere, a transport ship will automatically start hauling.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_construction_industry_02.jpg|10c57ab3790f3ec49abcb428aa55c780",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Construction Warehouse",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Construction Warehouses store Construction Material and Construction Rubble. Transport ships will automatically pick Construction Material from the warehouse once a construction site requests it. 

When dismantling or adjusting a modular building, Construction Rubble is produced. The Construction Warehouse automatically requests all existing Construction Rubble and once delivered will recycle it over time into Construction Material.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_construction_industry_03.jpg|4706279840815fc4483241754bf37059",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_conveyor_balancer"] = {
    identifier = "_base_conveyor_balancer",
    category_id = "_base_buildings",
    sidebar_text = "Conveyor Balancer",
    page_type = "PerCharacter",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Conveyor Balancer",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Conveyor Balancers are special buildings, part of the conveyor system. They have two input belt lanes and two output belt lanes, depending on use case they can be used to achieve multiple goals.

If both lanes on both sides are connected, the balancer will randomly scramble the two lanes depending on how the incoming items are aligned.

If you connect two inputs but only one output, the balancer will merge the two incoming belts together.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_balancer_merger.jpg|9add538144ccef745a7e3c442a2413bc",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "If you connect one input and both outputs, the balancer will act as splitter, distributing the incoming items evenly.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_balancer_splitter.jpg|3edefef51165a9f4482fac08078695d2",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Priority Levers",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[There are two levers which can be used to set priorities to either the left or right lane, both for input and output. With this you can modify the above mentioned cases to gain even finer control. When prioritizing a side the machine will always try to take or add items from or to that side first, and otherwise default to the other side.

For example you can have a merger that always prioritizes one input side or have a splitter that only outputs to one lane when the other lane is full.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_balancer_prio.jpg|45c21e36aad4d734b8e59c771a29e618",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Filter",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The balancer can be used to filter a certain item type from all incoming belts and only output it on the prioritized output side. By default the filter is disabled. Enable it by clicking the center button to select an item.

<b><color=red>The output priority lever needs to be set to left or right, otherwise the filter will not be applied.</color></b>]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_balancer_filter.jpg|e1e33f7b4537d264e992be9540a2f071",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_conveyor_drag_mode"] = {
    identifier = "_base_conveyor_drag_mode",
    category_id = "_base_ui",
    sidebar_text = "Belt Drag Mode",
    sort_order = 300,
    page_type = "Global",
    is_unlocked_by_default = true,
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Conveyor Belt Drag Mode",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[FOUNDRY features an advanced conveyor belt drag mode to quickly build the conveyors your factory needs.

Once you have the straight conveyor belt item equipped, hold down the left mouse button to start dragging from the current belt position. Aim towards any desired destination point and the game will automatically suggest a conveyor belt path. It does this by creating L-shaped belts to reach your target.

<b>Once in drag mode the game interface shows you all possible actions and their hotkeys, take a look at the bottem center UI above the hotkey bar.</b>]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/idb_drag_belt_3.png|04cf20ff9b3125c4db6ebb38ca742dbf",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Fixed Points",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Sometimes an L-shape isn't enough to get to your target as there might be something blocking the way. To solve this you may set so-called "fixed points". Once you place a fixed point (key: <action=Conveyor Smart Drag Set Fixed Point>), the game locks the current path and allows you to drag another L-shape from the last placed fixed point. You can place as many fixed points as you like.

If needed there is an option to remove the last placed fixed point (default key: <action=Conveyor Smart Drag Clear Fixed Point>).]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/idb_drag_belt_1.png|40b9041b3af22f84c94f970e50d2d305",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Up & Down",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[You can raise or lower the drag plane (keys: <action=Conveyor Smart Drag Move Drag Plane Up> & <action=Conveyor Smart Drag Move Drag Plane Down>), which will trigger the automatic creation of slopes up or down. Depending on your target this isn't always possible, but the game will try to get as close as possible.

Note: The slope conveyor item can also be dragged, but uses a much simpler drag mode without support for curves. Sometimes it can be useful to swap to the slope item.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/idb_drag_belt_4.png|0f4116ead1cede3459c2a1a37a1069e6",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Automatic Slopes",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "In addition to moving the drag plane manually, the drag mode will automatically try to build bridges over single voxel tall obstacles. Just drag across another belt and if there is enough space for slopes, they are automatically suggested.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/idb_drag_belt_2.png|ae75352e95a7cf74599baaa91e89a184",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Backwards Drag Mode",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[There are two different drag modes: Forward and Backward. Toggle them by pressing the key for switching drag modes (default: <action=Toggle Drag Mode>).

The backwards drag mode behaves slightly different so that it is easy for you to drag a belt in reverse direction. This is useful when you are currently at the end of your desired belt or if you want to extend an existing belt backwards.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
