  ["_base_conveyors"] = {
    identifier = "_base_conveyors",
    category_id = "_base_general",
    sidebar_text = "Conveyor Belts in Detail",
    page_type = "Global",
    is_unlocked_by_default = true,
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Conveyor Belt Curves",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "In FOUNDRY there is only one base conveyor belt (straight). It automatically gets converted to a curve if required. Curve ruleset: If a straight belt has an incoming belt from only one of the sides and none from behind, it'll convert to a curve.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/conveyor_curve.jpg|1209c3f2d132f6e4d864de19b9e7c481",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Side-Loading Belts",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[You can move items from one belt to another with what is called a side-loading belt, see the following example image. In the case below no curve is created because there is an incoming belt from behind.
Note: The directly-connected belt from behind will take priority over the side-loading belt, if you need more specific control over the flow you can use a conveyor balancer to merge conveyor belts.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
