        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/conveyor_sideloader.jpg|0d11e637a1afff54294d97e1b04a1cf1",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "T-Merge",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "The example below again does not create a curve because there are incoming belts from both sides. It can be used to merge two belts, however you cannot control which side takes priority.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
