      },
    },
  },
  ["_base_crafting"] = {
    identifier = "_base_crafting",
    category_id = "_base_ui",
    sidebar_text = "Crafting",
    sort_order = 200,
    page_type = "Global",
    is_unlocked_by_default = true,
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Crafting",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The inventory & crafting frame (hotkey <action=Inventory>) provides an overview of all currently unlocked crafting recipes. With research you can unlock more recipes.

The recipes are grouped by category, which can be switched by pressing the category bar buttons at the top.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_crafting.jpg|66c7d489b14b53041b24a4ad0864a37d",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = true,
        imageTextData = {
          {
            text = "Categories",
            bottomLeftAnchor = {
              x = 0.27,
              y = 0.53,
            },
            topRightAnchor = {
              x = 0.51,
              y = 0.64,
            },
            textColor = {
              r = 1,
              g = 0.501961,
              b = 0,
              a = 1,
            },
            autoSizeMax = 72,
            hasCenteredHorizontalAlignment = false,
            hasRightHorizontalAlignment = false,
            useFontWithoutOutline = false,
          },
        },
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The number at the bottom right corner of each recipe shows the maximum amount of craftable items. If this number is zero, the slot has a slight red tint.

If you hover over a crafting recipe, you will get a tooltip with the required inputs. The inputs may have three different colors:
-Green: Items are in inventory.
-Yellow: Items missing in inventory, but can be crafted.
-Red: Items missing in inventory and cannot be crafted.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/crafting_tt_new.jpg|9ac00688a4b58284f8b3ae2122d0916b",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_data_cable_system"] = {
    identifier = "_base_data_cable_system",
    category_id = "_base_general",
    sidebar_text = "Data Cable System",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Data Cable System",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "The Data Cable System allows to link multiple machines and create custom logic behavior based on conditions. A typical use case is to remote control (enable/disable) machines, but it can be used for a wide range of cases. Creating custom logic conditions is not a requirement in FOUNDRY, but often useful for expierienced players who want even more control.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Examples",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[- Shut down machines once a container is filled to a certain limit.
- Burn / destroy items before a container overflows by remote controlling belts/loaders or pumps.
- Control lights with a light switch.
- Create custom counters to track how many of certain items have been created.
- More detailed generator prioritization based on custom conditions like how much your batteries are filled up.
- Creative use cases like toggling lights based on time of day.
- And much more...]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "How it works",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Data Cables are an object you can build. They are similar to pipes, but there is only one piece that automatically connects to all surrounding data cables or the machines with data cable connections.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_dcs_02.png|2894594e2e86e9a4b95c5767fb772006",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Connected cables create a shared data network. A network consists of signals, and each signal has a value. There is a signal for each item, liquid and gas type, and on top of that there are custom signals which are named after numbers, letters and colors. Signal values are whole numbers ranging from negative two billion to positive two billion. By default every signal has a value of zero. The value zero is a special number, indicating that the signal isn't active and makes it invisible.

Data networks are updated 60 times per second. Signal values do not persist, they are only existent as long as they are continuously written by any source.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_dcs_03.png|8b6c2d194d0ea4547a67d1a17898e2f8",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Interaction and Configuration",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[To inspect a data network use your tablet and look towards a data cable, it will show you any non-zero signals currently present.

Once a data cable has been connected to machine, open the tablet, point at the connected machine and press the hotkey (default: ALT + left click) to open the machine configuration frame. If you equip the data cable, the game will automatically highlight all possible data cable connections in your vicinity. Additionally you can check the machine tooltip in the inventory to see if a machine has a data cable connection port.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_dcs_04.png|bbaae527c8bd17b41b95261b79dc64ae",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Example Setup",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[In most cases you will have certain machines that output something, and other machines that read that input and act accordingly. Let's say you want a loader to stop moving items once a logistics container has been filled to a certain amount, here's how to do it:

- Connect the loader to the logistics container via data cable.
- Logistics containers will automatically broadcast their inventory to the data network, therefore you don't need to configure the logistics container.
- Configure the loader by using the tablet to open the loader's data system configuration frame. Enable the "Enable based on condition" option. You will be presented with three slots to configure. For the first slot select the item you want to check for. For the second slot configure the condition operator, select "smaller or equals". Finally set the desired amount as constant in the third slot, for example 200. 

Now your loader will stop working as soon as ther are more than 200 items in the logistics container.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_dcs_01.png|87881967b0d680646b09546fea4da04a",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Special Data System Machines",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[- Data Processor: Allows to perform arithmetical operations on signals.
- Data Evaluator: Allows to evaluate and process conditions. 
- Data Source: Those act as signals sources, there is a static signal source that will constantly output the same signals and there is a lever version that can be toggled easily.

All machines are configured by using the tablet and opening the data system config frame.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_dcs_05.png|91c57952f77a49c4ba7b0d251a7038e5",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_drill_ship"] = {
    identifier = "_base_drill_ship",
    category_id = "_base_general",
    sidebar_text = "Drill Ship",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Drill Ship",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The Drill Ship is a tunnel boring machine. Once crafted you can place it anywhere in the world just like you would place a building. Use the demolition mode to deconstruct it if needed.

Once placed you can control and steer the Drill Ship from the inside. Go inside through one of the hatches and you'll find various controls to interact with.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Controls",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[<b>- Turning:</b> Use the two wheels on the left and right side to turn the Drill Ship, for each time you click it will rotate 90 degrees in that direction.
<b>- Set Dig Direction:</b> The Drill Ship can dig forward, up or down. Use the central lever to set the desired direction.
<b>- Set Dig Distance:</b> Before you start the Drill Ship you should configure the distance it should dig. Use the central textpad to configure how many voxels it should dig.
<b>- Start Digging:</b> Use the big green button to start the Drill Ship. It will dig for as many voxels as you configured, or until it hits an obstacle.
<b>- Stop Digging:</b> You can stop your Drill Ship at any time by pressing the smaller red button.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Inventory & Fuel",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Drill Ships need fuel (any item with a fuel value works) and also have an internal inventory for everything they mine. Both can be accessed through the \"Inventory + Fuel\" button.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_drone_controller"] = {
    identifier = "_base_drone_controller",
    category_id = "_base_general",
    sidebar_text = "Excavation Drone Controller",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Excavation Drone Controller",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The Excavation Drone Controller is a handheld tool that allows you to designate mining areas. There are multiple modes (single block, cube drag mode, ...) which can be switched through the radial menu. 

Whenever the character is close enough to a designated mining area, personal excavation drones will automatically excavate the marked blocks. The drones are automatically unlocked together with the same Omni-Analyzer unlock that grants the drone controller.

To remove designated mining areas you have two options: While having the Excavation Drone Controller equipped you can either swap into the removal mode, which allows you to remove areas the same way you set them, or you have the option to globally remove all designated mining areas. The respective hotkeys are be displayed on screen.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Toggle Excavation Drones",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[While having the tool equipped you can toggle (enable/disable) the personal excavation drones. This can be useful for cases where you first want to mark the area without the drones starting right away.

If you disable the drones, they will stay disabled until you re-enable them.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_energy_1"] = {
    identifier = "_base_energy_1",
    category_id = "_base_general",
    sidebar_text = "Foundation & Low Voltage Energy",
    page_type = "PerCharacter",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Building Parts and Energy",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[In FOUNDRY there are two different types of power, low and high voltage, this page is about low voltage power.

Low-voltage power is distributed through building blocks. Every low-voltage machine that is placed on top of building blocks will automatically be connected to the low-voltage grid of the building blocks. As long as the building blocks are connected, they all share the same low-voltage power grid.

Most machines (f.i. Drone Miner, Assembler, ...) require low voltage. If an object requires high-voltage power it will specifically say that in its tooltip. 

To power a low-voltage-grid you have multiple options:
At the beginning you may use Biomass Burners or Burner Generators, which will directly power the grid they are placed on.
Later you will get more efficient high-voltage power generation methods, which then is relayed by a transformer into low-voltage-power.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
