  ["_base_exploration"] = {
    identifier = "_base_exploration",
    category_id = "_base_general",
    sidebar_text = "Exploration / Omni-Analyzer",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Omni-Analyzer",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The Omni-Analyzer provides access to various exploration-based unlocks and improvements. Most of them are for convenience, but some of them will improve your factory as well.

You need to find and gather various objects in the world to progress and unlock the respective improvements. Read the text on the Omni-Analyzer UI frame for hints where to find each object.

Soon you will unlock the Short Range Scanner (which has its own info database page once it's unlocked), which allows you to track down specific required objects. The scanner has its own UI frame (default key: <action=Short Range Scanner>) which also provides you with additional information on where to find objects of interest.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_exploration_01.png|6cb0ae66aa1f9044cab00a953c110ae2",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "\"Wait, I only wanted to build factories!\"",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "We don't want to reveal too much, but in case you're not a fan of exploration mechanics we want to let you know that it won't take up a lot of your time, and ultimately it can be fully automated.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_filter_loader"] = {
    identifier = "_base_filter_loader",
    category_id = "_base_buildings",
    sidebar_text = "Filter Loader",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Filter Loader",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[A Filter Loader is a loader that needs to be configured to a certain item and will then exclusively move the configured item.

This can be useful if you want more granular control over the loaders behavior, regular loaders move any item they can get access to.]],
