  ["_base_flare_stack"] = {
    identifier = "_base_flare_stack",
    category_id = "_base_buildings",
    sidebar_text = "Flare Stack",
    page_type = "PerCharacter",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Flare Stack",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The Flare Stack's purpose is to destroy unwanted liquids and gases by burning them off. Whatever pipe you connect to a Flare Stack, it will draw in its contents and destroy them.

Some of the chemical recipes create unwanted byproducts like waste gas, use the Flare Stack to get rid of them.]],
        image = nil,
