  ["_base_flashlight"] = {
    identifier = "_base_flashlight",
    category_id = "_base_general",
    sidebar_text = "Flashlight",
    page_type = "PerCharacter",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Flashlight",
