        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "For better vision at night your robot comes with an integrated flashlight. The button/indicator for it can be found at the bottom right of the screen. The key to toggle it is <action=Spotlight>.",
