  ["_base_fracking_tower"] = {
    identifier = "_base_fracking_tower",
    category_id = "_base_buildings",
    sidebar_text = "Fracking Tower",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Fracking Tower",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The Fracking Tower is a modular building that is able to convert depleted or partially depleted ore veins into endless sources of ore.

The building needs to be placed on top of an ore vein (does not need to touch it, just needs to be on top). Once turned on it will extend a drill downwards until it reaches the vein. As long as the building remains supplied with sufficient Fracking Liquid all Ore Vein Miners which have already hit the ore vein core are now able to continue mining. The Fracking Liquid consumption depends on the amount of miners drilling the core.

For more information about Ore Vein Mining visit its respective info database page.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_frackingTower01.png|9dbf6f7ab75693a409d667b582df495e",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Struts",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "For aesthetic reasons the Fracking Tower extends struts into the ground once powered and turned on to look more anchored. Those struts can be removed / regenerated through the screen panel if they get in your way - their purpose is exclusively visual.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_frackingTower02.png|5e2e1beb2324e21459eb4f8a36880b8c",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_freight_elevator"] = {
    identifier = "_base_freight_elevator",
    category_id = "_base_buildings",
    sidebar_text = "Freight Elevator",
    page_type = "PerCharacter",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Freight Elevator",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The Freight Elevator allows the vertical transportation of items, it's intended to be used in cases where using Conveyor Slopes would be inconvenient.

It consists of two parts, a top and a bottom part. They are both built with the same item by switching the mode with the radial menu (hold <action=Alternate Action>).
It does not matter which part you place first, after placement you'll get a highlighted area (blue columns in image below), indicating where the elevator shaft will be. Pointing towards it with the opposite part selected will automatically snap it to the correct position, you only have to point at the desired height.

<b><u>Note:</u></b> Once both parts are placed, the freight elevator automatically excavates all terrain in its way. However the shaft area between the two parts needs to be free of buildings or any other blocking objects before they connect to each other.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_freightElevator_i.jpg|002d13fd9e71c4445b8df0a20cab5c60",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Once both parts are built you need to connect Loaders at both ends so that the Freight Elevator can interact with conveyor belts. You cannot add items from a machine directly to a Freight Elevator.

Freight elevators have an upwards and a downwards lane and both can be used in parallel. No matter on which part (top or bottom) you attach an Input Loader, the Freight Elevator will send it to the other end.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_freightElevator_ii.jpg|9afb13fc490e9b54fad3fa858d32e4fa",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_fuel_items"] = {
    identifier = "_base_fuel_items",
    category_id = "_base_general",
    sidebar_text = "Fuel Items",
    page_type = "Global",
    is_unlocked_by_default = true,
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Fuel Items",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Some buildings require fuel as power source. If an item can be used as fuel is indicated by its tooltip. Each fuel item has a different fuel value, the higher the more energy is produced when the item is consumed as fuel. More advanced fuel items that are more complex to produce are generally more efficient to use.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_fuel_item.jpg|3a91b6b96cdd1a241acc39feb571a10e",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Residual Items",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Some items which can be used as fuel leave a residual item once consumed. For instance the \"Ignium Fuel Rod\" leaves a \"Fuel Rod Casing\" once it's been used. You can check this by looking at the item's tooltip, if there is a residual item it's shown directly below the fuel value.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/residual_item_tt.jpg|beac3cb77af369d4b86892000037391a",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Residual items need to be removed from the machine or otherwise it will jam after the maximum amount has been reached.

<u><b>Important:</b></u> You need extra caution when automating usage of those items because output loaders do not know which item to take if multiple are available, they will take any. In this case you have to use Filter-Loaders, which are able to only move a certain item type.

Side note: Since generators/boilers do not produce any other items, you don't have to use filter loaders there.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_galactic_sales"] = {
    identifier = "_base_galactic_sales",
    category_id = "_base_general",
    sidebar_text = "Galactic Sales",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Galactic Sales",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[At the beginning you can only sell your products to casual customers through the sales platform. However this method of sales isn't as profitable and there is only a limited amount of products you can sell this way.

The way to avoid those drawbacks is to directly sell to planets throughout the galaxy. It is a little more complex, but it's worth it.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Getting Access To A Planetary Market",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The galaxy is separated into sectors and within sectors there are planets. Both need to be unlocked first.

To unlock a sector, click it and press the "unlock" button on the sector frame. The amount of sectors you can unlock depends on the antenna level of your space station.

To unlock a planet, click it and press the "acquire trade licence" button on the planet frame. Trade licences cost Firmarlite to acquire and the overall limit again can be increased by upgrading the offices on your station.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Supply Routes",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Once you acquired a trade licence you can start selling to a planet by configuring a supply route.

Supply Routes are per planet and per product type, you need to set it up for each product you want to sell.

All you need to do is to press the supply route button for the desired product on the planet frame and assign a cargo ship.

The amount of ships assigned (and the general demand of the planet) will determine how many robots you're able to sell.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Ship Fuel",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Space ships require fuel and the amount depends on how far the planet is away (can be seen on the planet info tab).

Fuel is calculated per item transported, so you do not have to worry about trade routes that are selling very few items. It is always calculated proportionally to your sales amount.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "How are items distributed?",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Planetary sales take priority over sales platform sales, as long as products can be sold to planets, your sales platform will never sell anything. You can keep it enabled to sell your excess products.

Distribution between multiple supply routes is proportionally, the products will be distributed to all your supplied planets in a roughly equal amount (relative to the overall demand).

Even though you might see space ships on the galaxy map, they are not actively moving items around. Instead your supply routes are simulated like the sales platform is per in-game hour. This is to ensure a constant and predictable sales behavior.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_geothermal_power"] = {
    identifier = "_base_geothermal_power",
    category_id = "_base_general",
    sidebar_text = "Geothermal Power",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Geothermal Power",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Geothermal Power is a very efficient way to generate power through Geothermal Vents & Boilers.

Inside the lava caves you can find Geothermal Vents, rocky formations which emit smoke.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/lava_cave_vent.jpg|801fcd7aa4741d445bc08718532a220e",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Once you found a Geothermal Vent you need to place a Geothermal Boiler on top of it in order to use it for power generation.

The Geothermal Boiler needs a special Ignium-based fuel to generate Steam at high efficiency.

Note: Since vents are rare, Geothermal Power is mostly a highly efficient supplementary power source instead of a full replacement for existing power generation methods.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/geothermal_boiler.jpg|405fd467fd5cb40448e6d167ec411d0c",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "How to find Vents?",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Use your handheld scanner to locate Geothermal Vents. But be aware, they are rare and you might need to explore to find them.

Once revealed by the scanner, Geothermal Vents are also visible on your map.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_incinerator"] = {
    identifier = "_base_incinerator",
    category_id = "_base_buildings",
    sidebar_text = "Incinerator",
    page_type = "PerCharacter",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Incinerator",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "The Incinerator can be used to destroy any solid item. You can both insert items manually or automate the process with Loaders.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_incinerator.jpg|9befe8d7f5822e74fb2ce6a4bfd705f5",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_jetpack"] = {
    identifier = "_base_jetpack",
    category_id = "_base_general",
    sidebar_text = "Jetpack",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Jetpack",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The jetpack allows easier movement around your factory at the cost of constant fuel consumption.

Once the jetpack has been unlocked through research you can double jump (press jump/ascend button twice) to enable the jetpack. Use the jump/ascend button (key: <action=Jump>) to ascend and the descend button (key: <action=Descend>) to descend. Landing or pressing the descend button twice will disable the jetpack.

The jetpack consumes more fuel while moving, indicated by the vertical bar on the right side of the jetpack HUD. Hovering without moving is pretty cheap!]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/jetpack_infodb.jpg|686fb3e0fcb172345b1a3a6fcda14195",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Note: If you previously unlocked the rocket boots (double jump ability), the jetpack will replace it whenever there is jetpack fuel available in your inventory. Without fuel, you are still able to rocket jump.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_lava_caves"] = {
    identifier = "_base_lava_caves",
    category_id = "_base_general",
    sidebar_text = "Lava Caves",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Lava Caves",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Deep down in the depths caves filled with lava are to be found. The enormous heat can be utilized for certain tasks, like smelting Firmarlite in a Lava-Smelter.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/lc1.jpg|66a1cb62cba19504c8d63fc48ebf84d8",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "How to get there?",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Most of the rock layers above the lava caves are too hard to dig or blast until you advance your Mining Hardness research. But there are ways around this problem: Throughout the world shafts of porous rock can be found. Your scanner and map will be able track them as soon as you research the elevator.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/lc2.jpg|b50eda9a574e0904185d733a10cabf2f",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Those porous rock shafts can be mined right away without the need for advancing your Mining Hardness research. Together with the elevator (which is able to dig on its own) you can use those shafts to get access to the lava caves.

The caves are found near the very bottom, so you want to configure the bottom elevator station roughly at a height between 2 and 15. Once you arrived down there, you will need to dig a couple blocks in any direction to reach the lava caves.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/lc3.jpg|152ca3fab6e41a648849d2cb271830fb",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Tips: 
- As soon as you unlock High-Voltage-Power, you can use the elevator to bring your power down into the caves. Each elevator station comes with a powerline connector.
- Freight elevators are also able to dig out their elevator shaft, but you need to place both the bottom and top part first before they will start digging.
- For more details about the elevators check their respective info database pages.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_long_range_scanner"] = {
    identifier = "_base_long_range_scanner",
    category_id = "_base_buildings",
    sidebar_text = "Long Range Scanner",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Long Range Scanner",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The Long Range Scanner is a modular building which gradually scans the surrounding area. It will reveal the map and all burried resources. It acts similar to the handheld scanner but has a much greater range.

Its main purpose is to uncover rare resources like the ore veins.

You can influence both its scan range and speed by the amount of additional modules you attach.

If multiple Long Range Scanners overlap their scan area, they will scan the area even faster.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_lrs.png|07f7d8d4ede34ad4ab2a8f4e1abde078",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_market"] = {
    identifier = "_base_market",
    category_id = "_base_general",
    sidebar_text = "Galactic Market",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Galactic Market",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[On the galactic market you can buy and sell various goods. 

Some items like construction material can be traded right from the start, others need to be unlocked through upgrading your space station. Not every item can be bought or sold on the market.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "One-Time-Trade Routes",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Simple an straight forward, you can manually order one of your ships to either buy or sell something.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Recurring Trade Orders",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[You can set up recurring orders, which will then automatically schedule idle cargo ships to trade with the market.

With recurring orders you can create rules like "sell every item of a certain type if more than X items are stored on the station". This is very useful to automate market trading, depending on your needs.

A recurring order can be paused, so you don't have to delete it in case you temporarily want to suspend one.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Cargo Space Ships",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[You need a cargo space ship to buy or sell from the market. The ship must not have any other task assigned.

<b>Important:</b> For recurring trade orders, each ship has its custom configuration toggle if it may be assigned to a recurring order. This configuration can be found on the ship frame, part of your station overview.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_mining_efficiency"] = {
    identifier = "_base_mining_efficiency",
    category_id = "_base_general",
    sidebar_text = "Mining Efficiency",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Mining Efficiency",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Every completed research of Mining Efficiency (endless research) let's you generate more ore per mining action. Mining action means whenever an ore item is generated by any of your mining buildings. Imagine you have reached 50% mining efficiency, that would mean for every second ore mined one additional free ore is generated (without it being removed from the ore source).

For ore vein core mining it means that less fracking liquid is consumed.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Pumpjack Efficiency",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "The Pumpjack Efficiency research behaves exactly like the Mining Efficiency.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_modular_buildings"] = {
    identifier = "_base_modular_buildings",
    category_id = "_base_general",
    sidebar_text = "Modular Buildings",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Modular Buildings & Construction Industry",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Modular buildings are big buildings or machines which are made up of smaller parts (called modules) and are then built by the Construction Industry buildings. By selecting which and how many modules a building should be using, you can customize both visuals and building behavior. The degree of customizability varies per building.

<u>This page handles how to build, adjust and remove modular buildings, to learn more about the Construction Industry buildings visit the respective info database page.</u>]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Constructing a Modular Building",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[To get started you need to handcraft what is called the modular building base. This item can be placed like any other building and acts as the starting point for your modular building.

Once you have placed your modular buiding base, you need the Modular Building Planner - a craftable handheld item that is used to configure modular buildings. Equip the Modular Building Planner, aim at the modular building base and click to open the visual editor.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_modular_buildings_01.jpg|a45a1232255c6a44db416c4b227e9aa0",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[In the visual editor you will see a lot of information about your building and a visual representation. On the left side info bar you can see all the information needed. It shows module information like minimum / maximum modules, the current configuration and the properties the final building will have.

Use the visual editor to add or remove modules. Click the red boxes to attach modules. A context menu will show you what can be attached at which attachment point. Click the existing modules to remove them, you'll be asked for confirmation. Hold down the left mouse button and move the cursor left or right to rotate the building preview. To help with building orientation the character's position is displayed in the editor.

Once your building configuration satisfies the requirements, it can be built. Before you build it you'll see the required construction costs at the side bar. For more details on the construction progress please visit the separate Construction Industry info database page.

Reminder: Once modular buildings are built, most of them still need to be turned on afterwards at the screen panel.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_modular_buildings_02.jpg|b5326e255a40b7d42a229720f914f786",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "How to adjust or demolish",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[If you want to change the properties of your modular building you can do this by using the Modular Building Planner and adjust it the way you want. Once you're done, confirm the changes and the Construction Industry will adjust your building. <b>Please note: Most buildings need to be shut down before they can be modified.</b>

Demolition works in a similar way: The visual editor has a button called "Dismantle Building" at the bottom of the side bar. This will trigger the Construction Industry to remove every module and will leave you with the base object you intially placed. Demolish the base object in the same way as you would demolish a regular building.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_overview"] = {
    identifier = "_base_overview",
    category_id = "_base_general",
    sidebar_text = "Overview",
    sort_order = 100,
    page_type = "Global",
    is_unlocked_by_default = true,
    paragraphs = {
      {
        paragraphType = "Header",
        header = "WELCOME TO FOUNDRY!",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Within this information database you will find detailed explanations on how to create a thriving space factory. <u>Please take a quick look at our <b>Quickstart page</b>, it's short and provides you with the most important information to get you started.</u>

<b><color=#0099ff>New pages will be unlocked as you progress.</color></b>

<b><u>Early Access:</u> These pages are going to be extended continously, if you encounter any wrong or missing information please let us know.</b>]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_personal_logistics"] = {
    identifier = "_base_personal_logistics",
    category_id = "_base_general",
    sidebar_text = "Xeno-Logistics",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Xeno-Logistics",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Xeno-Logistics allow you to restock your inventory from remote storage containers, called Xeno-Logistics Container as long as you're in proximity to a Xeno-Logistics Tower. Both the container and the tower are craftable buildings.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_logistics_container.jpg|12d2ff371b7512a488a39237111c57f2",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Requesting Items",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[You can set the requested amount for various items at your inventory frame below the inventory slots. As long as those items are available in any of the Xeno-Logistics Containers, the system will fill your inventory up to the desired amount (as long as there is space in your inventory).

Tip: The system can be temporarily disabled by pressing the toggle button on the top right above the request slots.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_logistics_ui.png|8af60da549ccaa046a304f74ed751334",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Xeno-Logistics Towers",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[For the automated resupply to work you need to be inside the coverage area of a powered Xeno-Logistics Tower. The coverage area of towers can be seen on the map, there is a toggle for them on the right side of the map frame.

Note: The coverage areas do not need to be connected. If you have a mining outpost, a single tower there is enough.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_logistics_tower.jpg|2ebbd944654dd0f448715e74ecf6ba5f",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
