  ["_base_pipes"] = {
    identifier = "_base_pipes",
    category_id = "_base_general",
    sidebar_text = "Pipes & Liquids",
    page_type = "PerCharacter",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Pipes",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Pipes are needed for the transportation of liquids and gases. Connected pipes combine into a single pipe network and they can only hold one unique type of liquid/gas. There are multiple pipe shapes (straight, curve, crossings, ...), they can be toggled by holding down right mouse button.

You can use the handheld tablet (hotkey <action=Toggle Tablet>) to open the Pipe Network Info Frame. Just click a pipe while your tablet is open.

<b><u>Check the Pipe Network Info Frame's info icon tooltips for more details about how the pipe system works.</u></b>]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/pipe_network_info_frame.png|aadb9c2360865284d89eb215b51c8bb1",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "To load or unload liquids connect a pipe to a pipe connection point at a machine. There are three different types of connections, inputs (red arrow), outputs (green arrow) and bidirectional connections (green cube). Bidirectional means that the content will both flow in and out depending on which side has a higher amount of content (regular flow).",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/tut_pipeConnectionPoints.jpg|8d72e16368239654b9914e3cc631e953",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = true,
        imageTextData = {
          {
            text = "Output",
            bottomLeftAnchor = {
              x = 0.03,
              y = 0.5,
            },
            topRightAnchor = {
              x = 0.5,
              y = 0.6,
            },
            textColor = {
              r = 0.576471,
              g = 0.996078,
              b = 0.00784314,
              a = 1,
            },
            autoSizeMax = 72,
            hasCenteredHorizontalAlignment = false,
            hasRightHorizontalAlignment = false,
            useFontWithoutOutline = false,
          },
          {
            text = "Input",
            bottomLeftAnchor = {
              x = 0.03,
              y = 0,
            },
            topRightAnchor = {
              x = 0.5,
              y = 0.1,
            },
            textColor = {
              r = 0.984314,
              g = 0,
              b = 0.0196078,
              a = 1,
            },
            autoSizeMax = 72,
            hasCenteredHorizontalAlignment = false,
            hasRightHorizontalAlignment = false,
            useFontWithoutOutline = false,
          },
          {
            text = "Bidirectional",
            bottomLeftAnchor = {
              x = 0.53,
              y = 0,
            },
            topRightAnchor = {
              x = 1,
              y = 0.1,
            },
            textColor = {
              r = 0.333333,
              g = 0.756863,
              b = 0.113725,
              a = 1,
            },
            autoSizeMax = 72,
            hasCenteredHorizontalAlignment = false,
            hasRightHorizontalAlignment = false,
            useFontWithoutOutline = false,
          },
        },
      },
      {
        paragraphType = "Header",
        header = "How to drain pipes",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "In case the wrong content got into a segment you can always quickly get rid of the content. On the pipe network info frame you can discard any content in by pressing the trash can button. This will clear the entire pipe network. Alternatively you can also use the Plumber Tool, which does the same but has a nice first person animation to make you feel  like a real plumber.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/tut_plumberTool.jpg|8372e90aa12814143866016634084b65",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Pumps & Network Complexity",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Each connected structure (like pipes or tanks) increase the complexity of a pipe network. Once the complexity limit is reached, the throughput of the network is severely limited. Pipe networks that exceed the complexity limit will glow red.

To avoid this problem you need to split your networks into smaller segments by separating them with pumps.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/tut_pump.jpg|5f0ecae279884124ab94e7a044e78e7b",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_pumpjack"] = {
    identifier = "_base_pumpjack",
    category_id = "_base_buildings",
    sidebar_text = "Pumpjack",
    page_type = "PerCharacter",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Pumpjack",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Pumpjacks are used to extract liquids from so called reservoirs (see details below). They need to placed on top (or slightly above) a reservoir and it will automatically start drilling for extractable liquids as soon as it's powered. Connect a pipe to move the extracted liquids.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_pumpjack.jpg|ee6765d155770314a83f494630205bbf",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Reservoirs",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Reservoirs are big spherical rocky objects, containing various sorts of rare liquids. They can be found by using your handheld scanner and they can be on the surface or burried in the ground. A reservoir cannot be removed by drilling or the use of explosives.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_reservoir.jpg|b075e1bc25cb54a45948f7db2d0173bd",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = true,
        imageTextData = {
          {
            text = "Olumite",
            bottomLeftAnchor = {
              x = 0.55,
              y = 0.5,
            },
            topRightAnchor = {
              x = 0.9,
              y = 0.7,
            },
            textColor = {
              r = 0,
              g = 0.6,
              b = 1,
              a = 1,
            },
            autoSizeMax = 72,
            hasCenteredHorizontalAlignment = false,
            hasRightHorizontalAlignment = false,
            useFontWithoutOutline = false,
          },
        },
      },
    },
  },
  ["_base_quickstart"] = {
    identifier = "_base_quickstart",
    category_id = "_base_general",
    sidebar_text = "Quickstart",
    sort_order = 95,
    page_type = "Global",
    is_unlocked_by_default = true,
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Quickstart",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[<b>Mining:</b> Terrain and ore blocks can be mined with your mining drill (which has to be equipped to be used).

<b>Crafting / Inventory:</b> Open your crafting menu and start crafting your first machinery. The required materials need to be in your inventory, crafted objects will be added to your inventory. Multiple crafting actions can be queued.

<b>Construction:</b> Equip a buildable item by either dragging it into your hotkeybar and pressing the according hotkey or by right-clicking it in the inventory. Move the building placeholder to your desired position and left-click to place it. Additional options are visible above your hotkeybar once the item is active.

<b>Demolition:</b> Enable demolition mode (hotkey <action=Demolish>) to remove structures, you'll get the removed object back into your inventory.

<b>First goals:</b> You should start with automating ore mining and start producing basic goods. More details at the task system on the top right. <u>Don't be afraid to build multiple machines for the same task, one or two will rarely suffice.</u>]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_research"] = {
    identifier = "_base_research",
    category_id = "_base_general",
    sidebar_text = "Research",
    page_type = "Global",
    is_unlocked_by_default = true,
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Research",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[To unlock new technologies and progress through the game you need to research. To conduct research in FOUNDRY you need two different things:

1. Science Packs: Those are items that fuel your research. Each technology requires a certain amount of Science Packs. Later on technologies need multiple different types of Science Packs at the same time. Science Packs can be produced in Assemblers and for the super early game you can craft them also by hand, but automating the Science Pack production should be one of your first priorities.
]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_research01.jpg|78144789774b8d74e84890ee53d332bc",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[2. Research Servers: Those are the buildings that consume the Science Packs. As soon as you select an active research (do this on your research screen, hotkey is <action=Research Frame>) all your active Research Servers will try to consume Science Packs and contribute to the active research. In case a research needs multiple different science packs a research server needs to have all of them available before it can function.

Research Servers are slow and you will need multiple to research at a satisfactory speed.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_research02.jpg|5115598975a025c4e9988fe84394df6d",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_resource_separator"] = {
    identifier = "_base_resource_separator",
    category_id = "_base_general",
    sidebar_text = "Resource Separator",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Resource Separator",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The Resource Separator can be used to get rid of unwanted byproducts from terraforming. It allows to convert Dirt, Stone, Seeds and similar items into various ores or Biomass.

It destroys the item inserted and not every item yields something. There is only a chance to find anything more valuable inside. It is not meant to be an efficient way of acquiring ores, but as an alternative to just destroying unwanted terrain blocks.

Note: Biomass just passes through the machine.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_short_range_scanner"] = {
    identifier = "_base_short_range_scanner",
    category_id = "_base_general",
    sidebar_text = "Short Range Scanner",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Short Range Scanner",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The Short Range Scanner is used for locating various artifacts that are needed for the exploration-based unlocks at the Omni-Analyzer (see "Exploration" page for more details).

Once unlocked at the Omni-Analyzer, the Short Range Scanner can be found on the top left of the screen, right next to the compass.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_shortrangescanner_01.png|3c6073544e742fc4f856bba473353a24",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The scanner always locks onto the closest object (shown in the first line) and tells you how far away it is.

"Distance" shows the horizontal distance, and the wheel guides you towards it. Position yourself so that the brightest slice is the top one and then walk in that direction until distance is close to 0.

"Vertical" indicates if the object is above or below your position.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Filtering",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "When hunting for specific things, it is important to make use of the filter mechanic. At the top left, next to the direction wheel, you can see the hotkey to open the Short Range Scanner UI (default key: <action=Short Range Scanner>).",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_shortrangescanner_02.png|9eb8d34cd3694144c9b71bfaab04c8ba",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[At this frame you can toggle specific object types, which makes it a lot easier to find what you're actually looking for. It's often useful to disable scanning for the small scrap pieces, as they often are in the way of finding more rare objects.

As you progress, more filter options will unlock.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_signs"] = {
    identifier = "_base_signs",
    category_id = "_base_buildings",
    sidebar_text = "Signs",
    page_type = "PerCharacter",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Signs",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "You can use Signs to label parts of your factory. There are wall-mounted and floor-mounted Signs, toggle them by using the radial menu (default key: hold <action=Alternate Action>). They are also available in different sizes.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/signs.jpg|575f51053638c1740a4659717663ba64",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Press the button on the edge of the Signs to open the frame to customize its text. Various styling tags including color tags may be used to create custom formatting (see screenshot).

By default the text size will be as big as possible to fully display your text. You can disable "Auto-Text-Size" to get exact control over the text size. This can be useful in case you want to keep it identical across multiple Signs with different texts.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/signs_setTextFrame.jpg|9f01353e7ab970845981abf2c026013a",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_smelters"] = {
    identifier = "_base_smelters",
    category_id = "_base_buildings",
    sidebar_text = "Smelters",
    page_type = "PerCharacter",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Smelters",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Smelters are used to process raw ore into metallurgic goods. Unlike other buildings like the Assembler, the Smelter does not require a crafting recipe to be set before it can be used. You or a loader can add any item that is "Smeltable", which is indicated in the item's tooltip.

Inserting any different smeltable item will automatically make the Smelter adjust to the new item, but its output inventory needs be empty before it can start to process the newly inserted item.

Note: Before you can use the quick-insert button on the machines screen panel, you need to manually insert the first item by using the "Manage Inventory" button (or by loader).]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_smelter.jpg|2ddd3f41e9e7f514596ce22c3d625dd7",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_solar_panels"] = {
    identifier = "_base_solar_panels",
    category_id = "_base_buildings",
    sidebar_text = "Solar Panels",
    page_type = "PerCharacter",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Solar Panels",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Solar Panels produce power during the day as long as they have sun exposure. The large solar panel produces at maximum output all day, while the small solar panel is  dependent on the sun angle and ramps up and down close to sunrise and sunset.

Once Solar Power is unlocked the compass displays the times you can viably generate energy with Solar Panels.

Solar Panels need a high voltage connection and they can be chained together.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_solarPanels.png|939adb6f94127ed4aa0d6a9baf166e86",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_space_station"] = {
    identifier = "_base_space_station",
    category_id = "_base_general",
    sidebar_text = "Space Station",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Space Station",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The space station is your connection to the galaxy. Its main purpose is to store and sell your products.

To get to the station view you need to build a station terminal and then press the "contact station" button on its screen panel. Later down the research tree you will be able to unlock ways to remotely open the station view.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_station.png|10c4540706cff4a4296f654e9ede9666",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Station Upgrades",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[There are many upgrades and improvements you can build on your station, expanding it is key to success.

Station upgrades need construction material, which is initially stored at the station and later has to be bought from the galactic market. Ultimately you will be able to produce your own construction material.

Some station upgrades need power and other upgrades, like the solar panels, provide you with additional power.

Construction speed is dependent on your Construction Drone Bay level, it's advised to upgrade it whenever possible to keep station construction times low.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Station Storage",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Your station has an internal inventory. The cargo capacity can be increased through station upgrades.

The capacity for Firmarlite - the galactic currency - can be exceeded infinitely, but you will be charged with external storage fees. You can find a detailed breakdown in the finance window.

Moving items between the planet and the station is done by building a shipping pad on the planet. It then allows you to select the item and transfer direction. Any cargo ship assigned to "planetary shipping" will then automatically service your shipping pads.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Space Ships",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Through the station you can manage your space ship fleet. On the space ship window you buy, sell, rename and assign tasks to your space ships.

Note: Some ship tasks like supply routes are not assigned through the ship frame, but instead are assigned on the galaxy view.

New ship types can be unlocked by upgrading the station.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_station_ships.png|f19822ff34da0ea4caeecc1361a93b54",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Sales Platform",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The sales platform is the easiest way to sell your products as it will automatically sell (once per ingame hour) your products to casual customers.

For it to sell your products you need the product in your station's storage and selling of the specified product needs to be enabled (which can be done using the sales platform window).

However as you progress, selling through the sales platform isn't the best way as you'll earn less compared to selling to other planets. At this point you should use the sales platform only to sell excess resources. 

The sales platform always has the lowest sales priority, which means you don't have to disable it once you start selling to planets as those will always get prioritized. In such cases the sales platform will only sell what could not be sold to planets.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_sales_platform.jpg|5e36783a1bc324f48b769c2f603f2f6e",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Finances",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The finances window presents you with a bunch of account tables and chart overviews to help you manage your company.

It also provides you with an overview about other competitors in the galaxy.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_station_finance.png|8708e6c1c5736484b8c73e48fef83e5b",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_storages"] = {
    identifier = "_base_storages",
    category_id = "_base_buildings",
    sidebar_text = "Storages",
    page_type = "PerCharacter",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Storages",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "To store items you may use FOUNDRY's various storage objects. They differ by inventory slot size and by their option to be automated by connecting a loader and conveyor belt. Information about both can be found on the tooltip of the item.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_storages.jpg|89086c7d099cad542bc965fcde6121cd",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Our automatable storages are called Logistic Containers while the regular ones are called Chest and Container.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_tablet"] = {
    identifier = "_base_tablet",
    category_id = "_base_general",
    sidebar_text = "Tablet & Quick Actions",
    page_type = "PerCharacter",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Tablet & Quick Actions",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The tablet can be used to inspect objects and provides usability quick actions.

To inspect an object you need to look at it with your tablet equipped. Examples for objects where additional information can be obtained are: Pipes, Trees, Ores, Reservoirs.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/tablet.jpg|c61f875bc0eb3d64fb112314804d92be",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Copy & Paste Configuration",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The tablet allows you to copy and paste the configuration of the following buildings: All producing machines like Assemblers or Smelters, Loaders and Conveyor Balancers.

To <u>copy settings</u> you need to look at the object you want to copy settings from and press Shift + RMB.

To <u>paste settings</u> you need to look at the object you want to paste settings to and press Shift + LMB.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "<b><u>Enable copy & paste without tablet:</u></b> There is an option in the settings to also allow usage of those commands without having the tablet equipped. This saves you time as you don't have to open the tablet first, but you need to be a bit more careful to not randomly click while sprinting (since Shift is also used for sprint as default key).",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "<b><u>Note:</u></b> The tablet also shows \"Copy Building\" and \"Copy Building with Settings\" but those commands can be used all the time, even with something else equipped.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_task_info_acquire_ore"] = {
    identifier = "_base_task_info_acquire_ore",
    category_id = "_base_tutorial_tasks",
    sidebar_text = "Acquire Ore",
    sort_order = -20,
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Acquire Ore",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Before you can start building you need to acquire ore. There are two basic ores: Xenoferrite (Brown) & Technum (Blue). Their voxel blocks look very different from the average terrain and on top are a few extra ore chunks which will yield a lot of ore to get you started quickly.

You can use the map (default key: <action=Map>) to navigate to found ores once you have located them by using your ore scanner. You might be able to spot surface ores on the map without them being scanned, but using the scanner is highly recommended.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/advancedTaskInfo_Ore.jpg|4959fc8578427204b9929802ade6d573",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "What ore looks like:",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/advancedTaskInfo_OreScreenshot.jpg|d26ea73a24c54ee4a96b51aa730dac53",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "To mine an ore voxel block (can be mined multiple times) or ore chunk press and hold left mouse button while having the mining drill equipped and pointed at the target. You also need to be close enough.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Unknown resources",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Sometimes you'll uncover what will be marked as \"unknown resources\" on the map. As you progress, you'll eventually be able to locate and use those resources deposits.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_task_info_biomass_burner"] = {
    identifier = "_base_task_info_biomass_burner",
    category_id = "_base_tutorial_tasks",
    sidebar_text = "Biomass Burner",
    sort_order = -60,
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Power Generation & Biomass Burner",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[To supply your Drone Miner with power, build a Biomass Burner on the same foundation (Building Blocks) as your Drone Miner is placed on. Once supplied with fuel (Biomass) it will power all machines on the same foundation.

<u>For detailed information on the power system read the info database message called "Foundation & Low-Voltage-Energy".</u>]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/advancedTaskInfo_biomass_burner_and_drone_miner.jpg|9e9861feb845c2d4fbee4664248366d8",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Gather Biomass",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Biomass can be obtained from trees and plants, you can mine it the same way you mined your first ore chunks (pressing and holding down left mouse button while having your mining drill equipped).",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/advancedTaskInfo_biomass_mining.jpg|6aacf972df8ce82438dd8f0b64b3a8c6",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Insert Fuel into Biomass Burner",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Insert fuel by pressing the <u>auto-insert button</u>, which will add as much items as possible to the machine or by pressing <u>\"Manage Inventory\"</u> and drag the items manually for exact control on how many items to insert.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/advancedTaskInfo_biomass_burner_panel.jpg|430e73ec5b5c22440922386791e22f62",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_task_info_bot_production"] = {
    identifier = "_base_task_info_bot_production",
    category_id = "_base_tutorial_tasks",
    sidebar_text = "Bot Production & Shipping",
    sort_order = -170,
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Research Transport Bot Assembly & Shipping",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "This research will unlock your first product, a small transport bot, which we are going to sell on our space station. Since we need to transport the robot to the space station this research also unlocks shipping pads, which are used to move goods between the planet and the space station.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Repair Space Station Hangar Bay",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Repairing the hangar bay works the same way as the Emergency Repairs on the station worked: Go to the space station UI and select Station Upgrades on the nav bar on the bottom left. Find the respective upgrade and start it.

Upgrades cost construction material, but there is sufficient material left on the stations internal storage.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Cargo Ships & Tasks",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Once the hangar is repaired you will be able to open the ship management frame from the bottom left nav bar on the station frame.

This frame shows you an overview of all ships owned and their assigned tasks.

Select the Buy Ship button to acquire a cargo ship. Once bought use the button in the middle of the ship row to assign it a new task. Select "planetary shipping".

If a ship is assigned to planetary shipping, it will automatically service any shipping pad on the planet as soon as the on the pad configured conditions are met.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_ship_task.jpg|ce9487e3e1da62a4593a8fb32f6b4806",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Shipping Pads",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Shipping Pads are large structures which do not require a foundation or power. They can be hard to place on rough terrain, you should prepare a flat area to make it easier.

Once placed a shipping pad can be configured from its screen panel. Select the shipping direction and the item which should be moved.

After that you may configure the minimum amount of goods to be transferred by any cargo ship in case you want to. By default it's set to half the capacity of the shipping pad.

Once the configured condition is met, any cargo ship assigned to planetary shipping will automatically land at your pad and start moving items to the station.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_shipping_pad.jpg|3e2145715ed60b544b4c0cea24d19e7d",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_task_info_building_blocks"] = {
    identifier = "_base_task_info_building_blocks",
    category_id = "_base_tutorial_tasks",
    sidebar_text = "Building Blocks (Foundation)",
    sort_order = -40,
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Craft and build Building Blocks (Foundation)",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Open the inventory & crafting menu (key: <action=Inventory>) and click on the icon of the Building Block to craft it once. Once the crafting action is complete (you can see the progress on the bottom left corner of the screen) you will find the crafted item in your inventory on the right side of the frame.

You may right-click a crafting menu button to queue 5 actions of that item at once.]],
