      },
      {
        paragraphType = "Text",
        header = "",
        text = "To build the crafted Building Blocks you need to open your inventory (key: <action=Inventory>) and drag its icon into one of your hotkey bar slots. ",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
