        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Enter demolition mode (key: <action=Demolish>) and aim at the object you want to dismantle. A red highlighter box will appear. Hold down the left mouse button to dismantle your target.

The removed object will be placed in your inventory. In FOUNDRY you don't loose any items on dismantling, so feel free to expirement as much as you like.]],
