  ["_base_task_info_factoryProgress"] = {
    identifier = "_base_task_info_factoryProgress",
    category_id = "_base_tutorial_tasks",
    sidebar_text = "Factory Expansions",
    sort_order = -160,
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Expand the factory",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[This task doesn't add any mechanics you haven't dealt with before: Research more technology and expand your factory. To ensure things aren't getting tedious, you should automate the production of certain goods. 

To automate your factory further you will have to research and make use of the Assembler, which allows you to automate crafting of various goods.

Similar to the way you automated the Smelters you can automate the Assembler with Belts and Loaders, however an Assembler first needs to be configured at its screen panel.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_task_info_first_production_line"] = {
    identifier = "_base_task_info_first_production_line",
    category_id = "_base_tutorial_tasks",
    sidebar_text = "First Production Line",
    sort_order = -80,
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Your first production line",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[To automate your first production line you need to attach a Loader to both the Drone Miner and the Smelter. Afterwards place Conveyor Belts from the Output Loader (Drone Miner) to the Input Loader (Smelter).

A Loader acts as the connection between a Conveyor Belt and a machine, it can either move items from a machine to a Conveyor Belt (output) or from a Conveyor Belt to a machine (input).]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/advancedTaskInfo_automation.jpg|f93f3a796089293498bda8d7a41527ff",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Connecting multiple machines",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "To increase your material production you will need more miners and smelters. <b>You can use a single belt to connect multiple machines by building the loaders and belts in parallel:</b>",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/advancedTaskInfo_expandSmelters.jpg|1c308478a1417a647adc27d3a0377379",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Loaders will only add the amount of items necessary to keep a machine running instead of filling up the whole machine inventory, making it easy to supply multiple machines with the same belt.

<b>Note:</b> If you're having trouble completing this task, make sure the Loaders are properly configured ("output" on the drone miner loader and "input" on the smelter loader).]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_task_info_first_research"] = {
    identifier = "_base_task_info_first_research",
    category_id = "_base_tutorial_tasks",
    sidebar_text = "First Research",
    sort_order = -110,
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Research \"Emergency Beacon\"",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "To start a new research you need to open the research frame, this can be done by going to your research server and click the according button on the screen panel or by using the hotkey (key: <action=Research Frame>). The research frame can be opened from anywhere, you don't need to be at the location of your server.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/advancedTaskInfo_researchFrame.jpg|2cc9422422026f14fa7cfe576945d2dc",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[The research frame shows all available (yellow, at the top), unavailable (red) and finished researches (green, at the bottom).

Click the "Emergency Beacon" research icon and click the "Start Research" button to start researching.

Now you need to supply your research server with "Science Pack I" to do the research. The science packs can be handcrafted and added manually to the server, but you should automate its production and move them by Belts and Loaders to your server as soon as possible.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
