  ["_base_task_info_small_smelter"] = {
    identifier = "_base_task_info_small_smelter",
    category_id = "_base_tutorial_tasks",
    sidebar_text = "Small Smelter",
    sort_order = -70,
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Craft and build a Small Smelter",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Instead of using your drop pod's in-built smelter to make plates and rods you need to start using buildings, they are more efficienct and scalable.

Crafting and building the Small Smelter works exactly like the buildings before.

Smelters accept any item that is "Smeltable" (indicated in item's tooltips). You need to manually insert the first item by using the "Manage Inventory" button, this will cause the smelter to set the according crafting recipe. Afterwards you may use the quick-insert button to add more. If you want to change which ore a smelter should smelt, just insert a different ore and the smelter will automatically change the according crafting recipe.

Note: Once you hit automation the smelter will also automatically adjust its crafting recipe if a different ore is supplied by a loader.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
