  ["_base_task_info_smelt_ore"] = {
    identifier = "_base_task_info_smelt_ore",
    category_id = "_base_tutorial_tasks",
    sidebar_text = "Smelt Ore",
    sort_order = -30,
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Smelt Ore",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Your drop pod has two integrated smelters, one for each ore type. ",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/advancedTaskInfo_dropPod.jpg|2f201a821d0a29648b8a1cd279b764b4",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Each smelter has its own screen panel where you can insert the previously mined ore by pressing the top button. The smelters will start converting the ore into Xenoferrite Plates and Technum Rods. To take out the final products press the lower button on the screen panel.",
        image = nil,
