  ["_base_task_info_station_sales"] = {
    identifier = "_base_task_info_station_sales",
    category_id = "_base_tutorial_tasks",
    sidebar_text = "Station Sales",
    sort_order = -180,
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Sales Platform",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[To sell our products to casual customers passing by the station we need to build the sales platform. It's a station upgrade just like the others you built before. You will have to upgrade your solar panels first in case you're out of station power.

Once constructed you can open the sales platform frame from the station nav bar. You will have to enable the robots you want to sell on the sales platform. Once enabled the sales platform will automatically sell robots from the station inventory.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_sales_platform.jpg|5e36783a1bc324f48b769c2f603f2f6e",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Sales are happening after each completed ingame hour. You can see the clock on the left of the first person UI below the compass.

An ingame hour takes 75 seconds, and a full ingame day takes 30 minutes. Almost all values in the game are shown per real time hour for your convenience.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_task_info_station_terminal"] = {
    identifier = "_base_task_info_station_terminal",
    category_id = "_base_tutorial_tasks",
    sidebar_text = "Space Station Terminal",
    sort_order = -150,
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Craft and build the \"Space Station Terminal\"",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Craft a Space Station Terminal and place it on a foundation. The station terminal needs power, so ensure the foundation is powered.

Once operational go to the terminals screen panel and press the big "Contact Space Station" button. This will lead you to the company setup frame. 

Enter a company name and select your preferred logo and color to proceed.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_terminal.jpg|8515d99c78e257041a7a7109e927a036",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Initiate \"Emergency Repairs\"",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Your space station features many different functionalities, but before being able to use most, you will need to upgrade your station.

On the station UI, a column of buttons can be found on the bottom left. Click the "Station Upgrades" button to reveal a list of possible upgrades. At first this list shows categories which can be clicked to get to the nested individual upgrades.

Go to "Hull", select "Emergency Repairs" and start it.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
