  },
  ["_base_task_info_use_scanner"] = {
    identifier = "_base_task_info_use_scanner",
    category_id = "_base_tutorial_tasks",
    sidebar_text = "Equip & Use Ore Scanner",
    sort_order = -15,
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Equip Items",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Before you can use the ore scanner you need to equip it. There are two different ways of equipping an item.

Equip through hotkey bar: Open your inventory (key: <action=Inventory>) and drag the item you want to equip into any hotkey bar slot (bottom center of your screen). Once the item is in your hotkey bar you can press the according number key or use your scroll wheel to move the active slot to the left or right to equip the item.

Quick equip: Sometimes it's not worth dragging an item into your hotkey bar because it's only required rarely. For thoses cases you can open your inventory (default key: <action=Inventory>) and simply right-click the item to quick-equip it.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Use Ore Scanner",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Once you have the ore scanner equipped you need to click the left mouse button to perform a scan.

A radial scan wave will expand in all directions and highlight found ores on the scanner itself and also on your user interface.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
