        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/advancedTaskInfo_useScanner.jpg|fae0a4cea0232b34e85b809d5a17c4fb",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_trains_basics"] = {
    identifier = "_base_trains_basics",
    category_id = "_base_general",
    sidebar_text = "Trains",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Trains",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Trains offer a flexible solution for transporting large quantities of goods over long distances, automatically and in a predictable manner.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Quickstart",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Start by placing tracks according to your needs. Then add two or more Train Stations next to the tracks wherever you want your train to stop at. Assign a name to each station at its screen panel. Place Train Loading Stations directly adjacent to your Train Stations, you will need one per Train Wagon. Configure the Train Loading Stations to either load or unload items from or to the train.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_loop2.png|c4b19aabafacbe149993e2b9aa19fa54",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Next, place a Train Engine with one or more Train Wagons on the train tracks. On the Train Engine’s screen panel there is a schedule button, which allows you to configure the train’s autopilot mode. Add the Train Stations by their unique names, and set conditions such as "Wait until full" or "Wait until empty". Lastly, enable the Autopilot checkbox on the schedule frame and watch your train move accordingly.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_schedule.png|4c3c91591be26224b9219cf77aa39f1c",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "If you want a train to move both forwards and backwards, you need two engines, one facing forward at the head of the train and one facing back at the tail of the train. Alternatively, you can build a loop to allow your train to turn around.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_halfloop.png|2b001330bc8650245b16bfb84f321d01",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Basics",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[<b>Train Engine:</b> A locomotive that pulls other wagons. It can only move forward in autopilot mode (can move backwards if manually piloted) and stops directly at the Train Station. For trains that should move in both directions (for example when a single line connects two Train Stations without it being a loop), you need an outward facing engine on both ends of the train.

<b>Train Wagon:</b> A wagon that, depending on the type, can carry either solid or liquid/gaseous goods in large quantities. Several wagons can be chained to a single Engine. It's recommended to transport only one type of goods per one wagon for the ease of management.

<b>Train Station:</b> A building that needs to be placed next to the train tracks which then can be used as stops for the train’s autopilot mode. Trains can approach stations from both directions, you can use signals to force a certain approach direction.

<b>Train Loading Station:</b> A building that needs to be placed next to the train tracks, adjacent to a Train Station. It can be set to either load or unload goods from the wagon that stops directly by its side. One Train Loading Station is required per wagon of the train. Each Loading Station has its own internal storage, and must be loaded or unloaded using Conveyor Belts.

Here you can see a Train Station with two Train Loading Stations.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_stationwithloadingstation.png|58e80be4fd32c9a46b8ea91e32e3b53d",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Signals",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[If more than one train is using the same tracks or stations, Train Signals should be used to avoid collisions.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_signal1.png|1528496746ab9ab43ae5e037de4750cd",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Train Signals are attached to a side of a train track and they split the track into track segments (before and after the signal). Trains will not enter track segments in which there is already another train inside, and instead wait at the signal before the occupied track segment.

Track segments are visualized in different colors while having a signal equipped. It also shows you the allowed direction of travel. This allows you to verify that your segments are set up properly.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_trackviz.png|993ef5edca49d28449f20a2248799d36",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Signals are one way (on the right side of the train movement direction). If you want trains passing through a segment in both directions, you need signals on both sides of the track, both where the segment starts and ends.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_onewayvstwoway.png|10578f1fc08dbb9489ea9bc3505635fd",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Trains will always travel as far as possible, until they arrive at an occupied segment, where they will wait. You can place multiple signals to create smaller segments to allow higher train flow, however this generally is only advised for track segments where trains only travel in the same direction.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Chain Signals",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Chain signals are a more advanced version of signals. They only allow a train to enter a segment if the upcoming signal afterwards is also green. They are generally used to mark crossings as exclusive, as you wouldn’t want a waiting train to block a crossing. You can swap to Chain Signals by holding down the right mouse button while having the Train Signal item equipped.

Here you can see an example, chain signals are orange and regular signals are blue:]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_chainsignals.png|5a0a07ec491ade14098be011f77a9876",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_underground_mining"] = {
    identifier = "_base_underground_mining",
    category_id = "_base_general",
    sidebar_text = "Ore Vein Mining",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Ore Vein Mining",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Ores can be found in small ore patches all over the moon, but for large quantities of ore it's better to go look for ore veins. Ore veins are large connected pieces of terrain that expand from the depths up to the surface.

They are rare, therefore because of the limited range of the handheld scanner it takes some time to find them if you explore on foot.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_oreVeinMining01.png|59ef826031dd9724eaddbefdc1f04489",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "On the map they use a different icon compared to the regular ore patches.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_oreVeinMining02.png|b9df02a629a98924dade078dd3d73a64",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "An easier way to find them is the use of the Long Range Scanner modular building, which has its own info database page in case you want further information on how it works.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Mining Setup",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Ore veins have multiple spots where an Ore Vein Miner (a building) can be attached. Use your handheld scanner to find all those spots. Once located you need to dig or blast your way to those spots. Using the auto-digging elevator is advised to quickly get to the desired depths.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_oreVeinMining03.png|5ff1bc4e380ecb34fa8f50270b6248c2",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Once you cleared enough space around the minable spots, the ore vein miner needs to be positioned in a way so that the building can expand into the digable part of the ore vein. Once supplied with power the miner will drill into the ore vein and create a tunnel while generating ore.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_oreVeinMining04.png|cb017a0af0ecc8740b4c5cf166229fb3",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "After some time the ore vein miner will hit the ore vein core, where it will stop mining. However there is a way to convert an ore vein into an endless source of ore: Using a Fracking Tower. To learn more about it read its separate info database page after it is unlocked in science tier five.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_walkways"] = {
    identifier = "_base_walkways",
    category_id = "_base_buildings",
    sidebar_text = "Walkways",
    page_type = "PerCharacter",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Walkways",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Walkways are a tool to quickly build (elevated) movement paths around your factory. The walkway system consists of platforms, stairs and ledge pieces. They can be toggled by using the radial menu (hold <action=Alternate Action>).

The special mechanic of walkways is that they will automatically generate railings on all outer borders of your platforms, no matter the shape. This makes them easier to build and provides better visuals than f.i. building parts and custom railings.

Some buildings like doors and elevator stations remove the railings of adjacent walkways, so that they can be attached without obstructing movement.

Other (mostly big modular buildings) objects have walkways in-built. Player-built walkways can be connected to them and will attach correctly.

<b><u>Ledge pieces:</u></b> The ledge pieces exist to force the removal of the railings on a particular side, for example if you want to transition from a regular floor onto walkways. See image below for an example.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infoDB_walkways.jpg|5b3da2c544e19ef4f8ab72b02dabe330",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_where_resources"] = {
    identifier = "_base_where_resources",
    category_id = "_base_general",
    sidebar_text = "Resources & Map",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Resources in FOUNDRY",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Once you need additional ores you can find more ore patches underground. Use your handheld scanner to uncover map tiles and discover their hidden resources.

Some resources are not available right away, and others cannot be reached yet. Those are still uncovered by the map scanner, but displayed differently.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_map01.jpg|16b3777a846bf4e48800bf8d54f01d7b",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = true,
        imageTextData = {
          {
            text = "Unscanned Area (Fog)",
            bottomLeftAnchor = {
              x = 0.05,
              y = 0.87,
            },
            topRightAnchor = {
              x = 0.9,
              y = 0.97,
            },
            textColor = {
              r = 1,
              g = 1,
              b = 1,
              a = 1,
            },
            autoSizeMax = 16,
            hasCenteredHorizontalAlignment = false,
            hasRightHorizontalAlignment = false,
            useFontWithoutOutline = false,
          },
          {
            text = "Scanned Area (No Fog)",
            bottomLeftAnchor = {
              x = 0.225,
              y = 0.175,
            },
            topRightAnchor = {
              x = 0.8,
              y = 0.275,
            },
            textColor = {
              r = 1,
              g = 1,
              b = 1,
              a = 1,
            },
            autoSizeMax = 16,
            hasCenteredHorizontalAlignment = false,
            hasRightHorizontalAlignment = false,
            useFontWithoutOutline = false,
          },
        },
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[There are additional ore patches of all starting ores scattered around the world in positions that do not require you to progress through research, you will find them by exploring the map, however they can be quite a bit away.

<u>Unknown resource</u> means you need to progress through the research tree before you can use it. 

<u>Unreachable resource</u> means the resource is in a rock layer you cannot yet venture into. Increase your Mining Force research to become able to drill or blast harder rock layers.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_workstations"] = {
    identifier = "_base_workstations",
    category_id = "_base_buildings",
    sidebar_text = "Robot Workstations",
    page_type = "Global",
    paragraphs = {
      {
        paragraphType = "Header",
        header = "Robot Workstations",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Workstations are places where you can put your bots and robots to work, so that they can improve the factory. A workstation affects buildings in front of it. During construction the area it affects is visualized, any buildings which are at least partially inside can be improved by the workstation.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_workstation_01.jpg|4788d323f9e7326428cb343202851b45",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Once placed, you'll have to put a bot or robot into the workstation. Interact with the workstation to open the related UI. Not every bot/robot is able to improve every building, check their item tooltips to find out how each bot/robot can be used.

Important: Each building can only be affected by one workstation and stops working if it is inside the area of multiple workstations.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_workstation_02.png|1bc65f41548772747847f4b921070071",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Workstation Effects",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[<b>Speed:</b> Increases the speed at which the machine operates.

<b>Efficiency:</b> Produces "free" items from time to time. For machines like Assemblers this means that after every x-th (depending on effiency percentage) crafting action, another free crafting action will be instantly completed. For example if the efficiency percentage is 10%, after the 10th crafting action, a free 11th crafting action is instantly completed. For machines like miners this means it'll deplete the vein slower.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Image",
        header = "",
        text = "",
        image = "Assets/FoundryAssets/UI/InfoDatabase_Images/infodb_workstation_03.png|629c970d19fd9c943b8bbfad7e78d0ed",
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Xeno Power Cores",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "Advanced workstations have optional slots for Xeno Power Cores, allowing the effects of assigned bots/robots to be further boosted.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
    },
  },
  ["_base_xeno_power_plant"] = {
