      {
        paragraphType = "Header",
        header = "Reactor & Utilization",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "The Xeno Reactor is the heart of the facility, it requires Reactor Fuel Mix from a Reactor Fuel Mixer to operate. The reactor has a Utilization Target that must be set manually on its screen panel. This target determines how much Reactor Fuel Mix is consumed and how much Energized Reactor Compound is produced. It can be adjusted in steps of 10 percent (from 0-100%) at any time, allowing you to scale based on your factory's current requirements.",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Steam Generator",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = [[Energized Compound produced by the Xeno Reactor is fed into the Steam Generator along with large amounts of Water. The Generator then produces High-Pressure Steam for the High-Pressure Turbines and Depleted Reactor Compound, which can be fed back into the Xeno Reactor for increased efficiency.

Hint: Use the Pipeline Liquid Intake to draw in large amounts of water.]],
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Header",
        header = "Turbines & Cooling Towers",
        text = "",
        image = nil,
        overrideMaxHeight = false,
        customMaxHeightPx = 0,
        addImageText = false,
        imageTextData = {},
      },
      {
        paragraphType = "Text",
        header = "",
        text = "High-Pressure Steam is consumed by multiple High-Pressure Turbines to generate power. The higher the Utilization Target of the Xeno Reactor, the more turbines are required to fully process the Reactor's output (one Turbine per 10% reactor utilization). These turbines also create Exhaust Steam as a byproduct, which can be safely dispersed via a Cooling Tower (one Cooling Tower per five Turbines).",
